// Language Selector Logic
const langButton = document.getElementById('header-lang__button');
const langContainer = document.getElementById('header-lang');
const langOptions = document.querySelectorAll('#header-lang__all span');

if (langButton && langContainer) {
  // Toggle language dropdown
  langButton.addEventListener('click', (e) => {
    e.stopPropagation();
    langContainer.classList.toggle('header-lang-open');
    const allContainer = document.getElementById('header-lang__all-container');
    if (langContainer.classList.contains('header-lang-open')) {
      allContainer.style.height = 'auto';
    } else {
      allContainer.style.height = '0';
    }
  });

  // Close dropdown when clicking outside
  document.addEventListener('click', (e) => {
    if (!langContainer.contains(e.target)) {
      langContainer.classList.remove('header-lang-open');
      const allContainer = document.getElementById('header-lang__all-container');
      if (allContainer) allContainer.style.height = '0';
    }
  });

  // Handle language selection
  langOptions.forEach(option => {
    option.addEventListener('click', () => {
      const selectedLang = option.getAttribute('data-lang');
      const currentLang = langButton.getAttribute('data-current-lang');
      
      if (selectedLang !== currentLang) {
        // Update button text and data attribute
        const textMap = { 'fr': '🇫🇷 FR', 'en': '🇬🇧 EN' };
        langButton.textContent = textMap[selectedLang];
        langButton.setAttribute('data-current-lang', selectedLang);
        
        // Hide selected language from dropdown, show others
        langOptions.forEach(opt => {
          if (opt.getAttribute('data-lang') === selectedLang) {
            opt.style.display = 'none';
          } else {
            opt.style.display = 'flex';
          }
        });
        
        // Save to localStorage
        localStorage.setItem('yumi_lang', selectedLang);

        // Apply translations
        applyTranslations(selectedLang);
      }
      
      // Close dropdown
      langContainer.classList.remove('header-lang-open');
      const allContainer = document.getElementById('header-lang__all-container');
      if (allContainer) allContainer.style.height = '0';
    });
  });
}

function applyTranslations(lang) {
  const texts = translations[lang];
  if (!texts) return;

  // Update simple text elements
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    if (texts[key]) {
      // Check if it's the animated letter type
      if (el.getAttribute('data-i18n-letters') === 'true') {
        el.innerHTML = texts[key].split('').map(char => 
          char === ' ' ? '<span class=\"letter\">&nbsp;</span>' : `<span class=\"letter\">${char}</span>`
        ).join('');
      } else if (el.getAttribute('data-i18n-html') === 'true') {
        el.innerHTML = texts[key];
      } else if (el.getAttribute('data-i18n-words') === 'true') {
        el.innerHTML = texts[key].split(' ').map(word => 
          `<div class=\"word\">${word}</div>`
        ).join('<div class=\"word-space\">&nbsp;</div>');
      } else {
        el.textContent = texts[key];
      }
    }
  });
}

// Initialize language from local storage
document.addEventListener('DOMContentLoaded', () => {
  const savedLang = localStorage.getItem('yumi_lang');
  if (savedLang && document.getElementById('header-lang__button')) {
    const langButton = document.getElementById('header-lang__button');
    const langOptions = document.querySelectorAll('#header-lang__all span');
    
    const optionToClick = Array.from(langOptions).find(opt => opt.getAttribute('data-lang') === savedLang);
    const currentLang = langButton.getAttribute('data-current-lang') || 'fr';
    
    if (optionToClick && savedLang !== currentLang) {
      optionToClick.click();
    }
  }
});
